
.title-screen {
  width: 100%;
  max-width: 760px;
  margin: 0 auto;
  background: linear-gradient(180deg, #1a0f1e 0%, #0d0710 50%, #1a0f1e 100%);
  border: 2px solid var(--c-border);
  box-shadow: 0 0 30px rgba(139, 92, 246, 0.15), inset 0 0 80px rgba(0,0,0,0.5);
  font-family: var(--font-body);
  color: var(--c-text-primary);
  overflow: hidden;
  position: relative;
  min-height: 480px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

/* ── 背景粒子画布 ── */
.bg-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 1;
}

/* ── 光晕 ── */
.glow-orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(60px);
  pointer-events: none;
  z-index: 0;
}
.glow-orb-1 {
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, rgba(139, 92, 246, 0.12), transparent);
  top: -80px;
  left: -80px;
  animation: orbFloat1 8s ease-in-out infinite;
}
.glow-orb-2 {
  width: 250px;
  height: 250px;
  background: radial-gradient(circle, rgba(212, 168, 67, 0.08), transparent);
  bottom: -60px;
  right: -60px;
  animation: orbFloat2 10s ease-in-out infinite;
}

@keyframes orbFloat1 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(40px, 30px) scale(1.1); }
  66% { transform: translate(-20px, 50px) scale(0.9); }
}
@keyframes orbFloat2 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(-30px, -20px) scale(1.15); }
  66% { transform: translate(20px, -40px) scale(0.85); }
}

/* ── 主内容 ── */
.title-content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 20px;
  gap: 16px;
}

/* ── 装饰 ── */
.title-ornament {
  display: flex;
  align-items: center;
  gap: 8px;
}
.ornament-symbol {
  color: var(--c-gold-dim);
  font-size: 14px;
  animation: ornamentPulse 2s ease-in-out infinite;
}
.ornament-line {
  width: 60px;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--c-gold-dim), transparent);
}

@keyframes ornamentPulse {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}

/* ── 标题 ── */
.title-main {
  text-align: center;
  margin: 8px 0;
}
.title-text {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 2px;
}
.title-line {
  display: block;
}
.title-sub {
  font-family: var(--font-display);
  font-size: 14px;
  color: var(--c-text-muted);
  letter-spacing: 8px;
  text-transform: uppercase;
}
.title-primary {
  font-family: var(--font-display);
  font-size: 32px;
  font-weight: bold;
  color: var(--c-gold);
  letter-spacing: 6px;
  text-shadow:
    0 0 20px rgba(212, 168, 67, 0.4),
    0 0 60px rgba(212, 168, 67, 0.15),
    0 2px 4px rgba(0,0,0,0.5);
  animation: titleGlow 3s ease-in-out infinite;
}
.title-version {
  font-family: var(--font-mono);
  font-size: 11px;
  color: var(--c-text-muted);
  letter-spacing: 6px;
  margin-top: 4px;
}

@keyframes titleGlow {
  0%, 100% { text-shadow: 0 0 20px rgba(212, 168, 67, 0.4), 0 0 60px rgba(212, 168, 67, 0.15), 0 2px 4px rgba(0,0,0,0.5); }
  50% { text-shadow: 0 0 30px rgba(212, 168, 67, 0.6), 0 0 80px rgba(212, 168, 67, 0.25), 0 2px 4px rgba(0,0,0,0.5); }
}

/* ── 引语 ── */
.title-tagline {
  font-size: 13px;
  color: var(--c-text-secondary);
  text-align: center;
  line-height: 1.6;
  letter-spacing: 2px;
  font-style: italic;
  opacity: 0.8;
}

/* ── 开始按钮 ── */
.start-btn {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  padding: 0;
  margin: 8px 0;
  background: transparent;
  border: none;
  cursor: pointer;
  outline: none;
  width: 220px;
  height: 52px;
  transition: transform 0.3s ease;
}
.start-btn:hover {
  transform: scale(1.05);
}
.start-btn:active {
  transform: scale(0.97);
}
.start-btn.clicked {
  animation: btnClick 0.6s ease forwards;
}
@keyframes btnClick {
  0% { transform: scale(1); opacity: 1; }
  40% { transform: scale(1.08); opacity: 1; }
  100% { transform: scale(0.9); opacity: 0; }
}

.btn-border {
  position: absolute;
  inset: 0;
  border: 2px solid var(--c-gold-dim);
  clip-path: polygon(8px 0, calc(100% - 8px) 0, 100% 8px, 100% calc(100% - 8px), calc(100% - 8px) 100%, 8px 100%, 0 calc(100% - 8px), 0 8px);
  transition: all 0.3s ease;
}
.start-btn:hover .btn-border {
  border-color: var(--c-gold);
  box-shadow: 0 0 15px rgba(212, 168, 67, 0.3), inset 0 0 15px rgba(212, 168, 67, 0.1);
}

.btn-content {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  z-index: 1;
}
.btn-icon {
  font-size: 18px;
  animation: btnIconFloat 2s ease-in-out infinite;
}
.btn-label {
  font-family: var(--font-display);
  font-size: 16px;
  font-weight: bold;
  color: var(--c-gold);
  letter-spacing: 4px;
  text-shadow: 0 0 10px rgba(212, 168, 67, 0.3);
}

@keyframes btnIconFloat {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-3px); }
}

.btn-glow {
  position: absolute;
  inset: -4px;
  background: radial-gradient(ellipse at center, rgba(212, 168, 67, 0.15), transparent 70%);
  opacity: 0;
  transition: opacity 0.3s ease;
  pointer-events: none;
}
.start-btn:hover .btn-glow {
  opacity: 1;
}

/* ── 侵蚀度指示器 ── */
.erosion-indicator {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-top: 4px;
  padding: 6px 12px;
  background: rgba(0,0,0,0.3);
  border: 1px solid var(--c-border);
  border-radius: 3px;
}
.erosion-label {
  font-size: 10px;
  color: var(--c-corruption);
  font-weight: bold;
  letter-spacing: 1px;
  white-space: nowrap;
}
.erosion-bar-track {
  width: 120px;
  height: 6px;
  background: var(--c-bg-dark);
  border: 1px solid var(--c-border);
  border-radius: 2px;
  overflow: hidden;
}
.erosion-bar-fill {
  height: 100%;
  background: linear-gradient(90deg, #3b82f6, #a855f7, #dc2626);
  border-radius: 1px;
  transition: width 0.1s linear;
  width: 0%;
}
.erosion-value {
  font-size: 12px;
  font-weight: bold;
  color: var(--c-text-primary);
  min-width: 36px;
  text-align: right;
}
.erosion-pct {
  color: var(--c-text-muted);
  font-size: 10px;
}

/* ── 底部 ── */
.title-footer {
  position: relative;
  z-index: 2;
  padding: 8px;
  margin-top: 8px;
  font-family: var(--font-display);
  font-size: 10px;
  color: var(--c-text-muted);
  letter-spacing: 2px;
  opacity: 0.6;
}

/* ── 响应式 ── */
.mobile-break {
  display: none;
}
@media (max-width: 480px) {
  .title-primary { font-size: 24px; letter-spacing: 4px; }
  .title-sub { font-size: 11px; letter-spacing: 4px; }
  .title-version { font-size: 9px; letter-spacing: 3px; }
  .title-tagline { font-size: 11px; }
  .start-btn { width: 180px; height: 44px; }
  .btn-label { font-size: 14px; }
  .mobile-break { display: block; }
  .erosion-bar-track { width: 80px; }
}
