
.inventory-list {
  display: flex;
  flex-direction: column;
  gap: 5px;
}
.inv-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 6px 8px;
  background: rgba(0,0,0,0.15);
  border: 1px solid var(--c-border);
  border-radius: 3px;
  transition: border-color 0.2s;
}
.inv-item:hover { border-color: var(--c-border-bright); }
.inv-icon {
  font-size: 18px;
  width: 28px;
  text-align: center;
}
.inv-info {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 1px;
}
.inv-name {
  font-weight: bold;
  font-size: 12px;
}
.inv-desc {
  font-size: 10px;
  color: var(--c-text-secondary);
}
.inv-count {
  font-size: 12px;
  font-weight: bold;
  color: var(--c-gold);
  min-width: 30px;
  text-align: center;
}
.inv-actions {
  display: flex;
  gap: 3px;
}

.empty-state {
  text-align: center;
  padding: 24px;
  color: var(--c-text-muted);
  font-size: 13px;
}

.add-section {
  margin-top: 8px;
}
.add-form {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
}
.input {
  flex: 1;
  min-width: 80px;
  padding: 4px 8px;
  background: var(--c-bg-dark);
  border: 1px solid var(--c-border);
  color: var(--c-text-primary);
  font-family: var(--font-body);
  font-size: 12px;
  outline: none;
}
.input:focus { border-color: var(--c-border-bright); }
.input-num { max-width: 60px; }
