
.create-screen {
  width: 100%;
  max-width: 760px;
  margin: 0 auto;
  background: linear-gradient(180deg, #1a0f1e 0%, #0d0710 50%, #1a0f1e 100%);
  border: 2px solid var(--c-border);
  box-shadow: 0 0 30px rgba(139, 92, 246, 0.15), inset 0 0 80px rgba(0,0,0,0.5);
  font-family: var(--font-body);
  color: var(--c-text-primary);
  overflow: hidden;
  position: relative;
  min-height: 480px;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
}

.bg-canvas {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  pointer-events: none;
  z-index: 1;
}

.glow-orb {
  position: absolute;
  border-radius: 50%;
  filter: blur(60px);
  pointer-events: none;
  z-index: 0;
}
.glow-orb-1 {
  width: 300px;
  height: 300px;
  background: radial-gradient(circle, rgba(139, 92, 246, 0.12), transparent);
  top: -80px;
  right: -80px;
  animation: orbFloat1 8s ease-in-out infinite;
}
.glow-orb-2 {
  width: 250px;
  height: 250px;
  background: radial-gradient(circle, rgba(212, 168, 67, 0.08), transparent);
  bottom: -60px;
  left: -60px;
  animation: orbFloat2 10s ease-in-out infinite;
}

@keyframes orbFloat1 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(-30px, 30px) scale(1.1); }
  66% { transform: translate(20px, 50px) scale(0.9); }
}
@keyframes orbFloat2 {
  0%, 100% { transform: translate(0, 0) scale(1); }
  33% { transform: translate(30px, -20px) scale(1.15); }
  66% { transform: translate(-20px, -40px) scale(0.85); }
}

.create-content {
  position: relative;
  z-index: 2;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 24px 20px;
  gap: 12px;
}

.title-ornament {
  display: flex;
  align-items: center;
  gap: 8px;
}
.ornament-symbol {
  color: var(--c-gold-dim);
  font-size: 14px;
  animation: ornamentPulse 2s ease-in-out infinite;
}
.ornament-line {
  width: 60px;
  height: 1px;
  background: linear-gradient(90deg, transparent, var(--c-gold-dim), transparent);
}
@keyframes ornamentPulse {
  0%, 100% { opacity: 0.6; }
  50% { opacity: 1; }
}

.create-title {
  font-family: var(--font-display);
  font-size: 22px;
  color: var(--c-gold);
  letter-spacing: 4px;
  text-shadow: 0 0 15px rgba(212, 168, 67, 0.3);
  text-align: center;
}
.create-subtitle {
  font-size: 12px;
  color: var(--c-text-secondary);
  letter-spacing: 2px;
  text-align: center;
  font-style: italic;
  margin-top: -4px;
}

.placeholder-content {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  padding: 20px;
  background: rgba(0,0,0,0.2);
  border: 1px dashed var(--c-border);
  border-radius: 4px;
  width: 100%;
  max-width: 360px;
}
.placeholder-icon {
  font-size: 36px;
  animation: floatIcon 3s ease-in-out infinite;
}
@keyframes floatIcon {
  0%, 100% { transform: translateY(0); }
  50% { transform: translateY(-6px); }
}
.placeholder-text {
  font-size: 14px;
  color: var(--c-text-secondary);
  text-align: center;
}
.placeholder-hint {
  font-size: 11px;
  color: var(--c-text-muted);
  text-align: center;
  line-height: 1.6;
}

.placeholder-form {
  width: 100%;
  max-width: 360px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.pf-row {
  display: flex;
  align-items: center;
  padding: 8px 12px;
  background: rgba(0,0,0,0.15);
  border: 1px solid var(--c-border);
  border-radius: 3px;
}
.pf-label {
  font-size: 12px;
  color: var(--c-text-muted);
  letter-spacing: 1px;
  text-transform: uppercase;
  min-width: 50px;
}
.pf-input {
  flex: 1;
  text-align: right;
  font-size: 12px;
  color: var(--c-text-muted);
  font-style: italic;
}
