
.section { margin-bottom: 10px; }
.section-subtitle {
  font-size: 11px;
  font-weight: bold;
  color: var(--c-text-secondary);
  margin-bottom: 4px;
  text-transform: uppercase;
  letter-spacing: 1px;
}
.empty-section { margin-bottom: 10px; }
.empty-state {
  text-align: center;
  padding: 12px;
  color: var(--c-text-muted);
  font-size: 12px;
  font-style: italic;
  border: 1px dashed var(--c-border);
}

.nearby-list {
  display: flex;
  flex-direction: column;
  gap: 3px;
}
.nearby-item {
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 4px 6px;
  background: rgba(0,0,0,0.15);
  border-left: 3px solid var(--c-purple);
  font-size: 12px;
}
.nearby-name { font-weight: bold; color: var(--c-gold); white-space: nowrap; }
.nearby-status { color: var(--c-text-secondary); flex: 1; }

.interact-card {
  background: rgba(34, 197, 94, 0.05);
  border: 1px solid rgba(34, 197, 94, 0.3);
  padding: 8px;
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.int-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 4px;
  font-size: 12px;
  color: var(--c-text-secondary);
}
.int-label {
  color: var(--c-text-muted);
  font-size: 10px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  margin-right: 4px;
}
.int-hp-row, .int-favor-row {
  display: flex;
  align-items: center;
  gap: 6px;
}
.int-hp-row .progress-bar, .int-favor-row .progress-bar { flex: 1; height: 12px; }
.int-val { font-weight: bold; font-size: 13px; color: var(--c-gold); min-width: 40px; }
.int-details {
  display: flex;
  flex-direction: column;
  gap: 3px;
  font-size: 12px;
  color: var(--c-text-secondary);
}
.int-actions {
  display: flex;
  gap: 4px;
  flex-wrap: wrap;
  margin-top: 4px;
}

.relation-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.relation-item {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 6px;
  background: rgba(0,0,0,0.15);
  border: 1px solid var(--c-border);
  font-size: 12px;
}
.rel-name { font-weight: bold; color: var(--c-gold); white-space: nowrap; min-width: 50px; }
.rel-role { color: var(--c-border-bright); font-size: 11px; min-width: 40px; }
.rel-bar { flex: 1; height: 10px; max-width: 120px; }
.rel-desc { color: var(--c-text-secondary); font-size: 11px; flex: 1; }
