
.meta-bar {
  display: flex;
  justify-content: space-between;
  padding: 4px 0 8px;
  font-size: 11px;
  color: var(--c-text-secondary);
  border-bottom: 1px dashed var(--c-border);
  margin-bottom: 8px;
  gap: 8px;
  flex-wrap: wrap;
}
.meta-icon { margin-right: 4px; }

.corruption-bar { margin-bottom: 8px; }
.corruption-bar .progress-bar { height: 16px; }

.stats-grid {
  display: flex;
  flex-direction: column;
  gap: 6px;
}
.stat-row {
  display: flex;
  align-items: center;
  gap: 6px;
}
.stat-label {
  min-width: 44px;
  font-size: 12px;
  color: var(--c-text-secondary);
  white-space: nowrap;
}
.stat-value {
  font-weight: bold;
  font-size: 14px;
  color: var(--c-gold);
  min-width: 40px;
}
.stat-row .progress-bar {
  flex: 1;
  height: 14px;
}

.status-tags {
  display: flex;
  gap: 6px;
  margin-top: 8px;
  flex-wrap: wrap;
}
.tag {
  padding: 2px 8px;
  font-size: 11px;
  border-radius: 3px;
  font-weight: bold;
}
.tag-temp {
  background: rgba(234, 179, 8, 0.2);
  border: 1px solid #eab308;
  color: #eab308;
}
.tag-perm {
  background: rgba(168, 85, 247, 0.2);
  border: 1px solid var(--c-purple);
  color: var(--c-purple);
}

.info-line {
  display: flex;
  gap: 6px;
  padding: 4px 6px;
  background: rgba(0,0,0,0.15);
  border-left: 3px solid var(--c-border-bright);
  margin-top: 4px;
  font-size: 12px;
}
.info-label {
  font-weight: bold;
  color: var(--c-gold);
  white-space: nowrap;
}
.info-text {
  color: var(--c-text-secondary);
}

.relation-list, .nearby-list {
  display: flex;
  flex-direction: column;
  gap: 3px;
}
.relation-item, .nearby-item {
  display: flex;
  gap: 8px;
  padding: 3px 6px;
  background: rgba(0,0,0,0.15);
  border-left: 3px solid var(--c-purple);
  font-size: 12px;
  align-items: center;
}
.rel-name, .nearby-name {
  font-weight: bold;
  color: var(--c-gold);
  white-space: nowrap;
}
.rel-role {
  color: var(--c-border-bright);
  font-size: 11px;
}
.rel-favor {
  font-weight: bold;
  font-size: 12px;
}
.rel-desc, .nearby-status {
  color: var(--c-text-secondary);
  flex: 1;
}

.task-list {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.task-item {
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 4px 6px;
  background: rgba(0,0,0,0.15);
  border-left: 3px solid var(--c-gold-dim);
  font-size: 12px;
}
.task-title {
  font-weight: bold;
  color: var(--c-gold);
}
.task-goal {
  color: var(--c-text-secondary);
  font-size: 11px;
}

.npc-card {
  background: rgba(34, 197, 94, 0.05);
  border: 1px solid rgba(34, 197, 94, 0.3);
  padding: 6px;
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.npc-meta {
  display: flex;
  justify-content: space-between;
  font-size: 11px;
  color: var(--c-text-secondary);
}
.npc-hp-row {
  display: flex;
  align-items: center;
  gap: 6px;
}
.npc-hp-row .progress-bar {
  flex: 1;
  height: 12px;
}
.npc-details {
  font-size: 11px;
  color: var(--c-text-secondary);
  display: flex;
  flex-direction: column;
  gap: 2px;
}
