
.combat-panel {
  // 战斗特有的红色调边框
  border: 1px solid var(--c-crimson);
  box-shadow: inset 0 0 30px rgba(139, 0, 0, 0.1);
}

.setup-section {
  display: flex;
  flex-direction: column;
  gap: 10px;
}
.setup-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 6px;
}
.setup-field {
  display: flex;
  flex-direction: column;
  gap: 2px;
}
.setup-field label {
  font-size: 10px;
  color: var(--c-text-secondary);
  text-transform: uppercase;
  letter-spacing: 1px;
}
.input {
  padding: 4px 8px;
  background: var(--c-bg-dark);
  border: 1px solid var(--c-border);
  color: var(--c-text-primary);
  font-family: var(--font-body);
  font-size: 12px;
  outline: none;
}
.input:focus { border-color: var(--c-crimson-bright); }
.input-num { max-width: 80px; }

/* 战斗场景 */
.combatants {
  display: flex;
  align-items: stretch;
  gap: 8px;
  margin-bottom: 10px;
}
.combatant-card {
  flex: 1;
  padding: 8px;
  border: 1px solid var(--c-border);
  border-radius: 4px;
}
.combatant-card.ally {
  background: rgba(34, 197, 94, 0.05);
  border-color: rgba(34, 197, 94, 0.3);
}
.combatant-card.enemy {
  background: rgba(220, 38, 38, 0.05);
  border-color: rgba(220, 38, 38, 0.3);
}
.combatant-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 6px;
}
.combatant-name {
  font-weight: bold;
  font-size: 13px;
}
.combatant-level {
  font-size: 11px;
  color: var(--c-text-muted);
}
.combatant-stats {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.cs-row {
  display: flex;
  align-items: center;
  gap: 6px;
}
.cs-label {
  font-size: 11px;
  min-width: 32px;
  color: var(--c-text-secondary);
}
.cs-val {
  font-weight: bold;
  font-size: 13px;
  color: var(--c-gold);
}
.cs-row .progress-bar {
  flex: 1;
  height: 12px;
}

.vs-divider {
  display: flex;
  align-items: center;
  font-size: 20px;
  color: var(--c-crimson-bright);
  padding: 0 4px;
}

/* 行动按钮 */
.actions {
  display: flex;
  gap: 6px;
  margin-bottom: 10px;
  flex-wrap: wrap;
}
.actions .btn {
  flex: 1;
  min-width: 80px;
  padding: 6px 8px;
  font-size: 12px;
}

/* 日志 */
.log-section {
  margin-top: 8px;
}
.section-subtitle {
  font-size: 11px;
  font-weight: bold;
  color: var(--c-text-secondary);
  margin-bottom: 4px;
  text-transform: uppercase;
  letter-spacing: 1px;
}
.log-container {
  max-height: 160px;
  overflow-y: auto;
  background: rgba(0,0,0,0.3);
  border: 1px solid var(--c-border);
  padding: 6px;
  display: flex;
  flex-direction: column;
  gap: 3px;
}
.log-entry {
  font-size: 11px;
  font-family: var(--font-mono);
  padding: 2px 4px;
  border-left: 3px solid var(--c-text-muted);
}
.log-entry.log-attack { border-left-color: var(--c-exp-blue); color: #93c5fd; }
.log-entry.log-damage { border-left-color: var(--c-corruption); color: #fca5a5; }
.log-entry.log-defend { border-left-color: var(--c-hp-green); color: #86efac; }
.log-entry.log-special { border-left-color: var(--c-gold); color: var(--c-gold); font-weight: bold; }

.end-btn {
  width: 100%;
  margin-top: 8px;
  padding: 8px;
  font-size: 14px;
}
